UPDATE app_settings SET value = jsonb_set(value, '{history}', COALESCE(value -> 'history', '{}'::jsonb) || jsonb_build_object('person_wikimedia_enricher', jsonb_build_object('samples', '[]'::jsonb, 'p1', 0, 'p2', 0, 'updated_at', now()::text), 'organization_wikimedia_enricher', jsonb_build_object('samples', '[]'::jsonb, 'p1', 0, 'p2', 0, 'updated_at', now()::text), 'person_bio_generator', jsonb_build_object('samples', '[]'::jsonb, 'p1', 0, 'p2', 0, 'updated_at', now()::text))) WHERE key = 'queue_health_state';